// 1. EXTRAE EL NOMBRE (Importante para el PDF)
const inputData = $input.first().json;
const userName = inputData.Nombre || inputData.userName || inputData['Tu nombre'] || 'Cliente';

// 2. BUSCAR EL CONTENIDO
let rawText = inputData.output || inputData.summaryText || inputData.text || inputData.Plan;

// 3. SI ES ARRAY, TOMAR EL PRIMERO
if (Array.isArray(rawText) && rawText.length > 0) {
    rawText = rawText[0];
}

// 4. SI NO HAY TEXTO, DEVOLVER ERROR
if (!rawText) {
    return [{ json: { error: "No se encontró el texto del plan." } }];
}

// 5. CONVERTIR MARKDOWN A HTML
let html = rawText.replace(/^## (.*)/gm, '<h2>$1</h2>');
html = html.replace(/^### (.*)/gm, '<h3>$1</h3>');
html = html.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
html = html.replace(/---/gm, '<hr style="border: 0; border-top: 1px solid #eee; margin: 20px 0;">');
html = html.replace(/^- (.*)/gm, '<li style="margin-bottom: 5px;">$1</li>');
html = html.replace(/✅/g, '<span style="color: #28a745;">✅</span>');
html = html.replace(/⚠️/g, '<span style="color: #ffc107;">⚠️</span>');
html = html.replace(/☐/g, '<span style="color: #999;">☐</span>');

// 6. GENERAR FECHA CORTA PARA EL NOMBRE DEL ARCHIVO (Lógica Agregada)
const dateObj = new Date();
const day = String(dateObj.getDate()).padStart(2, '0'); // Día con dos dígitos (ej: 22)
const month = String(dateObj.getMonth() + 1).padStart(2, '0'); // Mes con dos dígitos (ej: 01)
const year = dateObj.getFullYear();
const formattedDate = `${day}-${month}-${year}`; // Resultado: 22-01-2025

// 6.1. GENERAR FECHA LARGA PARA EL CUERPO DEL EMAIL (Para que se lea bien)
const longDate = dateObj.toLocaleDateString('es-ES', { year: 'numeric', month: 'long', day: 'numeric' });

// 7. INSERTAR FECHA EN EL HTML
html = html.replace('[Fecha actual]', longDate);
html = html.replace(/\n/g, '<br>');

// 8. PLANTILLA FINAL HTML
const finalHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <style>
    body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; background-color: #f4f4f4; margin: 0; padding: 0; }
    .container { max-width: 600px; margin: 20px auto; background-color: #ffffff; padding: 30px; border-radius: 10px; box-shadow: 0 4px 6px rgba(0,0,0,0.1); }
    h1 { color: #333333; font-size: 24px; border-bottom: 2px solid #007bff; padding-bottom: 10px; }
    h2 { color: #007bff; font-size: 20px; margin-top: 25px; background-color: #f8f9fa; padding: 10px; border-left:5px solid #007bff; }
    h3 { color: #555; font-size: 18px; margin-top: 20px; }
    p, li { line-height: 1.6; color: #555555; }
    strong { color: #000; }
  </style>
</head>
<body>
  <div class="container">
    ${html}
  </div>
</body>
</html>
`;

// 9. RETORNAR
return [
  {
    json: {
      emailBody: finalHtml,
      userName: $('Edit Fields').first().json.Nombre,
      formattedDate: formattedDate
    }
  }
];

